        Collection<ConceptMergeSpec> conceptMergeSpecs = mps.conceptMergeSpecs();
        assert conceptMergeSpecs != null : "ConceptMergeSpecs of " + modelMerge + " is null!";
        return CollectionSequence.fromCollection(conceptMergeSpecs).findFirst(new IWhereFilter<ConceptMergeSpec>() {
          public boolean accept(ConceptMergeSpec it) {
            return (it.getClass().getName()).contains(mergePolicy);
          }
        });
